 box-shadow 0.2s ease;\n}\n\n.modal-input[_ngcontent-%COMP%]:focus {\n  outline: none;\n  border-color: var(--insteip-primary-light);\n  box-shadow: 0 0 0 3px rgba(51, 102, 204, 0.12);\n}\n\n.modal-input--code[_ngcontent-%COMP%] {\n  font-family: ui-monospace, monospace;\n  text-align: center;\n  letter-spacing: 0.2em;\n}\n\n.alert-success[_ngcontent-%COMP%] {\n  display: flex;\n  align-items: flex-start;\n  gap: 0.5rem;\n  padding: 0.75rem;\n  font-size: 0.6875rem;\n  font-weight: 600;\n  color: #065f46;\n  background: #ecfdf5;\n  border: 1px solid #a7f3d0;\n}\n\n/*# sourceMappingURL=data:application/json;charset=utf-8;base64, */"]
